#include <stdio.h>
#include <string.h>
#define MAX 100001
#define LEN 21

int main() {
    int n;
    scanf("%d", &n);
    char names[n][LEN], numbers[n][LEN];
    for (int i = 0; i < n; i++) {
        scanf("%s %s", names[i], numbers[i]);
    }
    int m;
    scanf("%d", &m);
    for (int i = 0; i < m; i++) {
        char name[LEN];
        scanf("%s", name);
        int found = 0;
        for (int j = 0; j < n; j++) {
            if (strcmp(names[j], name) == 0) {
                printf("%s\n", numbers[j]);
                found = 1;
                break;
            }
        }
        if (!found) {
            printf("Not found\n");
        }
    }
    return 0;
}

